import{_ as a,a as t,b as n,c as i}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as o,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Tambah Google Drive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/google-drive.md","filePath":"ms-MY/upload/google-drive.md","lastUpdated":1781962217000}'),r={name:"ms-MY/upload/google-drive.md"};function p(c,e,h,u,g,k){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="tambah-google-drive-channel" tabindex="-1">Tambah Google Drive Channel <a class="header-anchor" href="#tambah-google-drive-channel" aria-label="Permalink to &quot;Tambah Google Drive Channel&quot;">​</a></h1><h2 id="perkara-yang-perlu-disediakan-dahulu" tabindex="-1">Perkara Yang Perlu Disediakan Dahulu <a class="header-anchor" href="#perkara-yang-perlu-disediakan-dahulu" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan Dahulu&quot;">​</a></h2><p>Sebelum bermula, sediakan item ini:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Diperlukan</th></tr></thead><tbody><tr><td>Google account</td><td>Digunakan untuk akses Google Cloud dan authorize Google Drive</td></tr><tr><td>Google Cloud project</td><td>Digunakan untuk enable Drive API dan cipta OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>Digunakan oleh ImgBed untuk mendapatkan <code>Client ID</code>, <code>Client Secret</code> dan <code>Refresh Token</code></td></tr><tr><td>ImgBed domain anda</td><td>Digunakan untuk OAuth redirect URI. Ia mesti sepadan dengan domain sebenar yang anda gunakan.</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="step-1-enable-google-drive-api" tabindex="-1">Step 1: Enable Google Drive API <a class="header-anchor" href="#step-1-enable-google-drive-api" aria-label="Permalink to &quot;Step 1: Enable Google Drive API&quot;">​</a></h3><ol><li>Buka Google Cloud Console.</li><li>Cipta project baharu atau pilih project sedia ada.</li><li>Pergi ke <code>APIs &amp; Services</code>.</li><li>Klik <code>Enable APIs and Services</code>.</li><li>Cari <code>Google Drive API</code>.</li><li>Buka dan klik enable.</li></ol><h3 id="step-2-configure-oauth-consent-screen" tabindex="-1">Step 2: Configure OAuth Consent Screen <a class="header-anchor" href="#step-2-configure-oauth-consent-screen" aria-label="Permalink to &quot;Step 2: Configure OAuth Consent Screen&quot;">​</a></h3><ol><li>Dalam Google Cloud, buka <code>Google Auth Platform</code>.</li><li>Lengkapkan maklumat asas <code>Branding</code>, seperti app name, support email dan developer contact email.</li><li>Buka <code>Audience</code>.</li><li>Untuk kebanyakan self-hosted personal deployments, pilih <code>External</code>.</li><li>Jika memilih <code>External</code>, tambah Google account yang mahu diauthorize di bawah <code>Test users</code>.</li><li>Buka <code>Data Access</code>.</li><li>Tambah Google Drive permissions yang diperlukan.</li></ol><h3 id="step-3-cipta-oauth-2-0-client" tabindex="-1">Step 3: Cipta OAuth 2.0 Client <a class="header-anchor" href="#step-3-cipta-oauth-2-0-client" aria-label="Permalink to &quot;Step 3: Cipta OAuth 2.0 Client&quot;">​</a></h3><ol><li>Dalam <code>Google Auth Platform</code>, buka <code>Clients</code>.</li><li>Cipta client baharu.</li><li>Tetapkan application type kepada <code>Web application</code>.</li><li>Beri nama client yang mudah dikenali.</li><li>Untuk authorized JavaScript origins, masukkan ImgBed URL, contohnya:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Untuk authorized redirect URIs, masukkan:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="Create OAuth client" loading="lazy"></p><p><img src="'+t+'" alt="Enter domain and callback URL" loading="lazy"></p><p>Selepas client dicipta, copy nilai ini:</p><table tabindex="0"><thead><tr><th>Generated Value</th><th>ImgBed Field</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="step-4-isi-google-drive-channel" tabindex="-1">Step 4: Isi Google Drive Channel <a class="header-anchor" href="#step-4-isi-google-drive-channel" aria-label="Permalink to &quot;Step 4: Isi Google Drive Channel&quot;">​</a></h2><p>Dalam Upload Settings, pilih <code>Google Drive</code> dan isi:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Apa Yang Perlu Diisi</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mudah dikenali, contohnya <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID dari Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret dari Google Cloud</td></tr><tr><td>Refresh Token</td><td>Biarkan kosong buat masa ini. Dapatkan pada step seterusnya.</td></tr><tr><td>Root directory</td><td>Optional. Default ialah <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Fill client details in ImgBed" loading="lazy"></p><h2 id="step-5-dapatkan-refresh-token" tabindex="-1">Step 5: Dapatkan Refresh Token <a class="header-anchor" href="#step-5-dapatkan-refresh-token" aria-label="Permalink to &quot;Step 5: Dapatkan Refresh Token&quot;">​</a></h2><ol><li>Klik <code>Get Token</code>.</li><li>Pilih Google account yang mahu disambungkan.</li><li>Lengkapkan authorization prompts.</li><li>Callback page akan menunjukkan <code>Refresh Token</code>.</li><li>Copy token tersebut.</li><li>Kembali ke ImgBed dan paste dalam field <code>Refresh Token</code>.</li></ol><p><img src="'+i+`" alt="Copy Refresh Token after authorization" loading="lazy"></p><p>Jika kemudian anda menukar Google account, menukar OAuth client, atau authorization lama tamat tempoh, anda tidak perlu delete channel. Buka edit page dan klik <code>Reauthorize</code>.</p><h2 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h2><p>Selepas semua field diisi, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka Google Cloud</span></span>
<span class="line"><span>-&gt; Cipta atau pilih project</span></span>
<span class="line"><span>-&gt; Enable Google Drive API</span></span>
<span class="line"><span>-&gt; Configure Google Auth Platform</span></span>
<span class="line"><span>-&gt; Jika Audience ialah External, tambah Google account anda ke Test users</span></span>
<span class="line"><span>-&gt; Cipta Web application OAuth client</span></span>
<span class="line"><span>-&gt; Gunakan https://your-domain.com/api/oauth/google/callback sebagai redirect URI</span></span>
<span class="line"><span>-&gt; Isi Client ID dan Client Secret dalam ImgBed</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Sign in dengan Google dan authorize</span></span>
<span class="line"><span>-&gt; Copy Refresh Token dari callback page</span></span>
<span class="line"><span>-&gt; Paste kembali ke ImgBed dan save</span></span>
<span class="line"><span>-&gt; Upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const f=o(r,[["render",p]]);export{v as __pageData,f as default};
